import { getDatabase, runQuery, getOne, getMany } from '../database';

export interface Habit {
  id?: number;
  user_id: number;
  name: string;
  description?: string;
  goal?: string;
  reminder_time?: string;
  reminder_frequency?: string;
  reminder_enabled?: number;
  preferred_channel?: string;
  created_at?: string;
}

export interface HabitCompletion {
  id?: number;
  habit_id: number;
  completion_date: string;
  completed_at?: string;
}

export interface HabitWithStreak extends Habit {
  current_streak: number;
  total_completions: number;
  last_completion_date?: string;
}

export class HabitModel {
  /**
   * Create a new habit
   */
  static create(habit: Habit): number {
    const db = getDatabase();
    const stmt = db.prepare(`
      INSERT INTO habits (
        user_id, name, description, goal, reminder_time, 
        reminder_frequency, reminder_enabled, preferred_channel
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `);

    const result = stmt.run(
      habit.user_id,
      habit.name,
      habit.description || null,
      habit.goal || null,
      habit.reminder_time || null,
      habit.reminder_frequency || 'daily',
      habit.reminder_enabled !== undefined ? habit.reminder_enabled : 1,
      habit.preferred_channel || 'sms'
    );

    return result.lastInsertRowid as number;
  }

  /**
   * Find habit by ID
   */
  static findById(id: number): Habit | undefined {
    return getOne<Habit>('SELECT * FROM habits WHERE id = ?', [id]);
  }

  /**
   * Find all habits for a user
   */
  static findByUserId(userId: number): Habit[] {
    return getMany<Habit>(
      'SELECT * FROM habits WHERE user_id = ? ORDER BY created_at DESC',
      [userId]
    );
  }

  /**
   * Find habits with reminders enabled
   */
  static findWithRemindersEnabled(): Habit[] {
    return getMany<Habit>(
      'SELECT * FROM habits WHERE reminder_enabled = 1 AND reminder_time IS NOT NULL'
    );
  }

